import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/introduction.md","filePath":"zh/guide/introduction.md"}'),d={name:"zh/guide/introduction.md"};function i(c,e,l,n,s,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h1><h2 id="什么是-clearance" tabindex="-1">什么是 Clearance？ <a class="header-anchor" href="#什么是-clearance" aria-label="Permalink to &quot;什么是 Clearance？&quot;">​</a></h2><p>Clearance 是一个基于 <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a> 构建的、开箱即用的 Laravel 应用管理面板。它提供了一个 Livewire 4 + Flux UI 面板，用于管理权限、角色、看守器和设置，并附带一个上下文授权层和角色上限功能——通过一条 artisan 命令即可安装，且不改动任何 Spatie 数据表。</p><p>Clearance 为你提供：</p><ul><li><strong>管理面板</strong>，涵盖权限、角色、看守器、设置和仪表板——既可以使用预置路由，也可以单独嵌入每个 Livewire 组件。</li><li><strong>上下文授权</strong>——将角色或权限授予限定在特定模型实例的范围内（一个 Store、一个 Tenant、一个 Project），通过 <code>$user-&gt;canIn()</code>、<code>@canin</code>/<code>@hasrolein</code> 这两个 Blade 指令，以及可在 User 模型之外使用的 <code>ContextService</code>。</li><li><strong>上限角色（Ceiling roles）</strong>——一个角色可以声明一个父角色，其权限集合将作为上限；子角色的权限永远不会超出父角色，并在每次保存时自动强制执行。</li><li><strong>精细化的写权限</strong>——每个面板分区都有一个可单独委派的 <code>clearance-{section}-write</code> 权限，因此你可以只授予“管理角色”而不必同时授予“管理设置”。</li><li><strong>超级管理员</strong>，带有可选启用的全局 Gate 绕过、针对现有类管理员角色的别名检测，以及安全、非破坏性的提升。</li><li><strong>用户模块</strong>（可选启用）——从针对单个用户的面板中，将角色分配到全局或特定上下文，并支持按上下文设置权限覆盖。</li><li><strong>设置面板</strong>——针对每个角色/看守器的显示名称、描述、经过净化的 SVG 图标及颜色；一个支持自动分配与批量分配的可配置默认角色。</li><li><strong>看守器管理</strong>——数据库支持的看守器，在应用启动时注入到 <code>auth.guards</code>，且仅限于白名单内的驱动程序。</li><li><strong>内置 9 种语言</strong>（ar、en、es、fr、hi、it、pt、ru、zh），经过键一致性测试。</li><li><strong>可扩展钩子</strong>——<code>HasClearance</code> trait、<code>HasPermissionGroups</code> trait、<code>ClearanceContextable</code> contract，以及可复用的 Blade 组件。</li><li><strong>SVG 净化</strong>——每一个用户提供的图标在存储前都会经过一个白名单净化器处理。</li><li><strong>经过安全加固</strong>——在每一条授予权限的路径上都设有权限提升上限，拒绝优先的上下文覆盖机制，以及受保护的 <code>clearance-*</code> 命名空间。参见<a href="/clearance-docs/zh/guide/security.html">安全性</a>。</li></ul><h2 id="与-spatie-laravel-permission-的关系" tabindex="-1">与 spatie/laravel-permission 的关系 <a class="header-anchor" href="#与-spatie-laravel-permission-的关系" aria-label="Permalink to &quot;与 spatie/laravel-permission 的关系&quot;">​</a></h2><p>Clearance 并不是 Spatie 权限包的替代品——它是构建在其之上的 UI 与授权层。角色和权限依然是 Spatie 的 <code>Role</code> 和 <code>Permission</code> 模型，依然存储在 Spatie 的 <code>roles</code>、<code>permissions</code>、<code>model_has_roles</code>、<code>model_has_permissions</code> 和 <code>role_has_permissions</code> 数据表中。Clearance 从不修改这些数据表。Clearance 新增的一切内容——显示元数据、角色作用域、上限、上下文分配、按上下文的覆盖——都存放在它自己的一组 <code>clr_*</code> 数据表中。完整拆解请参见<a href="/clearance-docs/zh/guide/architecture.html">架构</a>。</p><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>依赖</th><th>版本</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>概述</th></tr></thead><tbody><tr><td>权限（Permission）</td><td>一个遵循 <code>group-action</code> 命名约定的 Spatie 权限（例如 <code>orders-create</code>）。授予某项能力。</td></tr><tr><td>角色作用域（Role scope）</td><td>每个角色要么是 <code>global</code>（直接分配、全局生效），要么是 <code>contextual</code>（绑定到特定模型类型，只能在某个上下文实例内分配）。</td></tr><tr><td>上限角色（Ceiling role）</td><td>一个角色可以声明一个父角色，其权限集合作为上限——子角色永远不会超出这个上限。</td></tr><tr><td>上下文（Context）</td><td>一个模型实例（一个 Store、一个 Tenant、一个 Project），角色或权限覆盖可以限定在其范围内。</td></tr><tr><td>覆盖（Override）</td><td>一个按用户、按上下文的 <code>forced_on</code>/<code>forced_off</code> 权限授予或拒绝——拒绝始终优先生效。</td></tr></tbody></table><p>以上每个概念都有对应的完整页面：<a href="/clearance-docs/zh/features/permissions.html">权限</a>、<a href="/clearance-docs/zh/features/roles.html">角色</a>、<a href="/clearance-docs/zh/features/contextual-authorization.html">上下文授权</a>、<a href="/clearance-docs/zh/features/users.html">用户</a>、<a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>准备好安装 Clearance 了吗？继续阅读<a href="/clearance-docs/zh/guide/installation.html">安装指南</a>。</p>',14)])])}const m=t(d,[["render",i]]);export{u as __pageData,m as default};
